SELECT AVG(time_velocity) AS avg_time_velocity
FROM mining_data
WHERE site_id = 1;

SELECT avg_coal_production, date_time
FROM mining_data
ORDER BY date_time DESC;

SELECT site_name
FROM mining_sites
ORDER BY site_name;

